#!/usr/bin/env bash
# Write testing/.env.test1 from environment (CI / VPS — never commit secrets).
#
# Required env:
#   TEST1_API
#   TEST1_CLAUDE_AGENT_API_KEY
#
# Optional: REPO_DIR (default: repo root from script location)
set -euo pipefail

REPO_DIR="${REPO_DIR:-$(cd "$(dirname "$0")/../.." && pwd)}"
ENV_FILE="$REPO_DIR/testing/.env.test1"

: "${TEST1_API:?TEST1_API is required}"
: "${TEST1_CLAUDE_AGENT_API_KEY:?TEST1_CLAUDE_AGENT_API_KEY is required}"

mkdir -p "$REPO_DIR/testing"
cat > "$ENV_FILE" <<EOF
# Generated by scripts/devops/ci_write_test1_env.sh — do not commit
SLOT_NAME="test1"
API="${TEST1_API}"
CLAUDE_AGENT_API_KEY="${TEST1_CLAUDE_AGENT_API_KEY}"
EOF
chmod 600 "$ENV_FILE"
echo "Wrote $ENV_FILE"
